import React, { useState } from 'react';
import axios from 'axios';
import '../assets/styles/Skype.css'; // Presupunem că stilurile pentru Skype se vor afla aici

const Skype = ({ onClose }) => {
  const [errorMessage, setErrorMessage] = useState('');
  const [activeSection, setActiveSection] = useState(null); // Stare pentru secțiunea activă (chats sau contacts)
  const [isMuted, setIsMuted] = useState(false); // Stare pentru microfon (muted/unmuted)
  const [isCameraOn, setIsCameraOn] = useState(false); // Stare pentru cameră (on/off)

  const handleSkypeAction = (endpoint) => {
    axios.post(`/shortcuts/skype/${endpoint}/`)
      .then(response => {
        console.log(response.data.message || 'Action performed successfully');
        setErrorMessage(''); // Resetăm orice eroare
      })
      .catch(error => {
        console.error('There was an error performing the action!', error);
        setErrorMessage('There was an error performing the action.');
      });
  };

  const toggleSection = (section) => {
    // Dacă secțiunea este deja activă, o dezactivăm; altfel, o activăm
    setActiveSection(activeSection === section ? null : section);
  };

  const toggleMute = () => {
    handleSkypeAction('toggle-mute');
    setIsMuted(!isMuted); // Inversăm starea microfonului
  };

  const toggleCamera = () => {
    handleSkypeAction('toggle-camera');
    setIsCameraOn(!isCameraOn); // Inversăm starea camerei
  };

  const confirmCloseSkype = () => {
    setActiveSection(null);
    handleSkypeAction('close-skype');
  };

  return (
    <div className="skype-container">
      <h1 className="title">Skype</h1>

      {/* Prima linie de butoane */}
      <div className="button-row">
        <button onClick={() => handleSkypeAction('open-skype')} className="button">
          <i className="fas fa-external-link-alt"></i> Adu în față
        </button>
        <button onClick={confirmCloseSkype} className="button">
          <i className="fas fa-times"></i> Închide Skype
        </button>
        <button onClick={() => toggleSection('chats')} className={`button ${activeSection === 'chats' ? 'active' : ''}`}>
          <i className="fas fa-comments"></i> Chats
        </button>
        <button onClick={() => toggleSection('contacts')} className={`button ${activeSection === 'contacts' ? 'active' : ''}`}>
          <i className="fas fa-address-book"></i> Contacts
        </button>
      </div>

      {/* Afișează butoanele pentru secțiunea Chats */}
      {activeSection === 'chats' && (
        <div className="button-group">
          <button onClick={() => handleSkypeAction('start-video-call')} className="button">
            <i className="fas fa-video"></i> Video Call
          </button>
          <button onClick={() => handleSkypeAction('start-audio-call')} className="button">
            <i className="fas fa-phone"></i> Audio Call
          </button>
          <button onClick={toggleMute} className="button">
            <i className={`fas ${isMuted ? 'fa-microphone-slash' : 'fa-microphone'}`}></i> {isMuted ? 'Unmute' : 'Mute'}
          </button>
          <button onClick={toggleCamera} className="button">
            <i className={`fas ${isCameraOn ? 'fa-video' : 'fa-video-slash'}`}></i> {isCameraOn ? 'Turn Off Camera' : 'Turn On Camera'}
          </button>
          <button onClick={() => handleSkypeAction('hang-up')} className="button">
            <i className="fas fa-phone-slash"></i> Hang Up
          </button>
          <button onClick={() => handleSkypeAction('next-conversation')} className="button">
            <i className="fas fa-arrow-right"></i> Next Conversation
          </button>
          <button onClick={() => handleSkypeAction('previous-conversation')} className="button">
            <i className="fas fa-arrow-left"></i> Previous Conversation
          </button>
        </div>
      )}

      {/* Afișează butoanele pentru secțiunea Contacts */}
      {activeSection === 'contacts' && (
        <div className="button-group">
          <button onClick={() => handleSkypeAction('navigate-up')} className="button">
            <i className="fas fa-arrow-up"></i> Săgeată Sus
          </button>
          <button onClick={() => handleSkypeAction('navigate-down')} className="button">
            <i className="fas fa-arrow-down"></i> Săgeată Jos
          </button>
          <button onClick={() => handleSkypeAction('start-video-call')} className="button">
            <i className="fas fa-video"></i> Video Call
          </button>
          <button onClick={() => handleSkypeAction('start-audio-call')} className="button">
            <i className="fas fa-phone"></i> Audio Call
          </button>
          <button onClick={toggleMute} className="button">
            <i className={`fas ${isMuted ? 'fa-microphone-slash' : 'fa-microphone'}`}></i> {isMuted ? 'Unmute' : 'Mute'}
          </button>
          <button onClick={toggleCamera} className="button">
            <i className={`fas ${isCameraOn ? 'fa-video' : 'fa-video-slash'}`}></i> {isCameraOn ? 'Turn Off Camera' : 'Turn On Camera'}
          </button>
          <button onClick={() => handleSkypeAction('hang-up')} className="button">
            <i className="fas fa-phone-slash"></i> Hang Up
          </button>
        </div>
      )}

      {errorMessage && (
        <div className="error-message">
          {errorMessage}
        </div>
      )}
    </div>
  );
};

export default Skype;
